const Q_ECONOMICS_2003=[{"id": "objective>Economics>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price of a good rises from ₦5 to ₦8 and the quantity demanded falls from 200 to 190 units. Over this price range, the demand curve is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using e = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">∆QD</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">∆P</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">P</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">QD</span> <br/>  <br/>                   = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">190 - 200</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 8 -5</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">5</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 200</span> <br/>  <br/>                    = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">- 10</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>  x <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">5 </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">200</span> <br/>  <br/>                        =  0.08 <br/> It is elastic or fairly elastic since price elasticity is always positive.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In economic analysis, a statement is said to be normative if it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can be tested scientifically</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relates to value judgment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is contradictory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is incorrect</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> normative statement expresses a value judgment about whether a situation is desirable or undesirable. An example of a normative economic statement is: \"The government should provide basic healthcare to all citizens.\"</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction derived from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, utility is the satisfaction or benefit derived by consuming a product; thus the marginal utility of a good or service is the change in the utility from an increase in the consumption of that good or service. So, utility is the satisfaction derived from consumption.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If there is an increase in demand without a corresponding increase in supply, there will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fall in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift in supply curve to the right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shift in demand curve to the left</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand for a commodity increases while supply remains constant,  there will be an excess demand over supply. This will lead to an increase in the equilibrium  price of the commodity as well as an increase in the equilibrium quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the production possibility curve of a country represented in the diagram below to answer this questions  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> An improvement in technology will enable the country to produce at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Point Z can only be attainable when there is an improvement in technology which will raise production. Technical progress will shift the ppc outward. </div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the production possibility curve of a country represented in the diagram below to answer this questions  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the country is currently producing at point Y, it can increase production of producer goods by moving to the point</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The country can move to point W since moving towards that point will increase the quantity produced due to opportunity cost.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Q</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\">8 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">MUy</td><td style=\"border:1px solid black;text-align:center;\">16</td><td style=\"border:1px solid black;text-align:center;\">14</td><td style=\"border:1px solid black;text-align:center;\">12</td><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">2 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">MUx</td><td style=\"border:1px solid black;text-align:center;\">11</td><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\">9</td><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">4</td></tr></table></div> <br/>  <br/> In the table above, the price of commodity y is ₦2 and that of x is ₦1 while the individual has an income of ₦12. Determine the combination of the two commodities the individual should consume to maximize his utility</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3y and 3x </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6y and 4x</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3y and 6x </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5y and 5x</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The individual can only maximize his income at 3y and 6x  <br/>  B = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span>X + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span>Y  which is the formula <br/>  <br/> Restated as P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span>Y + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span>X <br/>  = 3(2) + 6(1)  <br/>  = 6 + 6  <br/> =  ₦12 which is equivalent to the consumer's income</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When two variables are positively related, the graph of the relationship</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a straight line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a downward-sloping curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is an upward sloping curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a negative intercept</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is an upward-sloping curve (Upward sloping curve has a positive slope), the two variables being price and quantity such as  supply curve or abnormal demand curve.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For an inferior good, a decrease in real income lead to     </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an outward shift of the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an inward shift of the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a lowed equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in quantity demanded</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An inferior good is a type of good whose demand decreases when the consumer's income increases, and vice versa. Therefore, a decrease in real income would lead to an increase in the demand for the inferior good, which is represented graphically as an inward shift of the demand curve. Therefore, the correct answer is 'an inward shift of the demand curve'.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a planned economy, the emphasis is on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">individual choice and decisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public ownership and control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">private ownership and control</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices and competition</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A planned economy is one in which production, investment, prices, and incomes are determined centrally by the government.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Price elasticity of supply is a ratio of the change in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity supplied to the change in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">original quantity to a change in new quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity supplied to the change in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price to the change in quantity supplied</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price elasticity of demand is calculated as :<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\"> Percentage change in quantity  supplied </span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> Percentage change in price</span></div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run average cost curve is called a planning curve because it shows what happens to costs when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variable inputs are increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed factors are increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different sizes of plants are built</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bigger size of plants is built</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run average cost curve (LRAC) is often referred to as the 'planning curve' because it provides firms with a long-term view of their costs based on the assumption that all factors of production are variable. It shows the cost of output for different plant sizes, hence the correct answer is 'different sizes of plants are built'.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Imperfect market is characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">many buyers and few sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large number of buyers and sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-preferential treatment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfect mobility of factors of production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imperfect markets are characterized by having competition for market share, high barriers to entry and exit, different products and services, and a small number of buyers and sellers. </div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Short-run period in production is a period for a firm to be able to change its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variable inputs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total outputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">scale of operation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short-run period of production, a firm can only change its variable inputs. Variable inputs are those inputs whose quantity can be changed in the short run, such as labor and raw materials. The firm cannot change its total outputs, total revenue, or scale of operation in the short run because these are determined by the firm's fixed inputs, such as capital, which cannot be changed in the short run.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table below to answer this questions  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Output produced per day (unit)</td><td style=\"border:1px solid black;text-align:center;\">Fixed cost per day (₦)</td><td style=\"border:1px solid black;text-align:center;\">Total cost per day (₦)  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">100 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">30 </td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">120 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">130 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">135 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">150 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70 </td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">170 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">80</td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">190</td></tr></table></div> <br/>  <br/> The ATC at 30 units of output is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦120.000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3.00</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ATC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TC<hr size=\"1\" />Q</td></tr></table></div>  <br/>  at 30 units ATC =<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\"> 120</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">30 </span> <br/> = ₦4</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table below to answer this questions  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Output produced per day (unit)</td><td style=\"border:1px solid black;text-align:center;\">Fixed cost per day (₦)</td><td style=\"border:1px solid black;text-align:center;\">Total cost per day (₦)  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">100 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">30 </td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">120 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">130 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">135 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">150 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70 </td><td style=\"border:1px solid black;text-align:center;\">60 </td><td style=\"border:1px solid black;text-align:center;\">170 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">80</td><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">190</td></tr></table></div> <br/> At 60 units of output, the AVC is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦150.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦90.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1.50</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At 60 units of output, the AVC is <br/>  <br/> AVC = VC/output  <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">150 - 60</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">60</span> <br/>  <br/>  = ₦1.50</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand curve facing a firm is sharply downward sloping, the firm is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a perfect competitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopolistic competitor as it can have a limited influence on price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopolist as it can have a great influence on price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oligopolist as it can collude with other firms to have some influence on price</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve of a monopoly is downward sloping. The demand curve is also the Average Revenue curve.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A normal supply curve is usually positively sloped because the relationship between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand and price is positive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply and price is negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price and demand is negative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price and supply is positive</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A normal supply curve slope upward from left to right or slope downward from right to left indicating a positive slope.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best method of production in an under-populated country is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour-extensive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">land-intensive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital-intensive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour-intensive</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an under-populated country, the best method of production is capital-extensive. This is because in such countries, there is a scarcity of labour and an abundance of land. Therefore, methods of production that require less labour and more technology are more efficient.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insurance companies, pension and provident funds and unit thrusts are all examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government financial agencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-governmental organizations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-bank financial institutions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-based revenue mobilizers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nonbank financial companies (NBFCs), also known as nonbank financial institutions (NBFIs) are entities that provide certain bank-like and financial services but do not hold a banking license or is not supervised by a national or international banking regulatory agency. <br/>  <br/> Examples of nonbank financial institutions include insurance firms, venture capitalists, currency exchanges, some microloan organizations, and pawn shops. These non-bank financial institutions provide services that are not necessarily suited to banks, serve as competition to banks, and specialize in sectors or groups.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a firm, value added can be defined as the difference between the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">value of its output and the cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total revenue and total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">input prices and product prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value of its output and inputs purchased from other firms</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Value added is also known as output approach or method. In this method, national income is measured in terms of monetary value of goods and services produced in the country. The value of output less cost of inputs that is, sales value less inputs.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Securities are described as listed when they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bought and sold purely for development purposes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilized as short-term debt instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilized as long-term debt instrument</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traded on a recognized stock market</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A listed security is a financial instrument that is traded through an exchange, such as the NYSE or Nasdaq. When a private company decides to go public and issue shares, it will need to choose an exchange on which to be listed.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The commercial banks differ from non-bank financial institutions because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accept deposits withdrawable by cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilize savings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">invest surplus plus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contribute to economic development</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial banks provide short-term loans while non-bank financial institutions provide long term loans. (vii) Commercial banks provide current account facilities/ issue cheque books while non-bank financial institutions do not provide current account facilities/ Do not issue cheques books.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation that is usually associated with periods of trade boom is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand-pull inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creeping inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagnation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand-pull inflation is asserted to arise when aggregate demand in an economy outpaces aggregate supply. It involves inflation rising as real gross domestic product rises and unemployment falls, as the economy moves along the Phillips curve.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'Near Money' is best described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a financial assets that is convertible to cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a financial instrument that is readily convertible to cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government financial instrument that is convertible to cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time deposits with low interest rates</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Near money, sometimes referred to as quasi-money or cash equivalents, is a financial economics term describing non-cash assets that are highly liquid and easily converted to cash, such as bills of exchange,cheques,promissory note.it is the same as representative mone,  assets which can readily be converted into cash, such as bills of exchange.</div>", "topic": "MONEY : TYPES OF MONEY"}, {"id": "objective>Economics>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distinguishing characteristic between the money market and the capital market lies in whether the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">funds mobilized are private or public</div>", "<div style=\"font-family:Cambria;font-size:17px;\">securities are primary or secondary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt instruments provided are long-term or short-term</div>", "<div style=\"font-family:Cambria;font-size:17px;\">securities are in debentures of ordinary shares</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market is a financial market for the buying and selling of long-term debt or equity-backed securities. This market channels the wealth of savers to those who can put it to long-term productive use, such as companies or governments making long-term investments.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Nigeria's composite price index in 1999 was 140.03% and 144.05% in 2000, the rate of inflation in 2000 was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.02% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.10% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.06% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.03%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of inflation is calculated by finding the percentage change in the price index from one period to the next. In this case, the price index increased from 140.03% in 1999 to 144.05% in 2000.  <br/>  <br/> The percentage change is calculated as ((144.05 - 140.03) / 140.03) x 100  <br/>  <br/> = 4.02%. </div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The monetary control instrument most effectively used by the Central Bank of Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discount rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reserve ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margin requirements </div>", "<div style=\"font-family:Cambria;font-size:17px;\">open market operations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Currently, OMO is the major instrument of monetary policy at the CBN. Open market operation involves buying or selling government securities, such as treasury bills and bonds, in the open market to influence the liquidity position of banks.  <br/>  <br/> Other supporting instruments are discount window operations, moral suasion, forex sales and the standing facility introduced in December 2006.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major objectives of a revenue allocation formula in a country is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">share revenue between the public and private sectors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure the financial viability of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">share revenue between the different tiers of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divert revenue from areas of surplus to areas of need</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is used to share revenue between the different tiers of government. In Nigeria, it is administered by the Revenue Mobilization Allocation and Fiscal Commission.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effectiveness of devaluation as a solution to a balance of payments problems depends on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">relative elasticities of demand and supply of imports and exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign investments of businessmen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value of visible and invisible goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value of invisible items of both domestic and foreign trades</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of payments problems, also called a currency crisis, occurs when a nation is unable to pay for essential imports and/or service its debt repayments. Typically, this is accompanied by a rapid decline in the value of the affected nation's currency. The effectiveness of this devaluation depends on the relative elasticities of demand and supply of imports and exports, and its attendant inflows of foreign currency.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">IBRD as an international monetary institution is concerned with the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balance of payments problems of member nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financing of private business in member nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of infrastucture in member nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improvement of trade among member nation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The International Bank for Reconstruction and Development is an international financial institution that offers loans to middle-income developing countries.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of the sole proprietorship over the partnership form of business organization is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It enjoys limited liability for debt in the event of failure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its existence is limited by an individual's lifespan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It relies on the decision of friends to succeed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The possibility of conflict in management is virtually non-existent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of a sole proprietorship over a partnership is that you aren't liable for the actions of your partners. The possibility of conflict in management is virtually non-existent since that it is a one-man business.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distinction between capital and recurrent expenditure lies in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amount of expenditure involved</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of the revenue generated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of the goods and services to be provided</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time frame of the expenditure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distinction between capital and recurrent expenditure lies in the time frame of the expenditure. Capital expenditure is used for acquiring or improving long-term assets like equipment, buildings, or land. Recurrent expenditure is used for regular and ongoing operational costs such as salaries, rent, utilities, etc.  <br/>  <br/> The key difference between the two is how long their effects last, which means the time frame of the expenditure .</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under a floating exchange rate regime,the determinant of the exchange rate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the system of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand for and supply of foreign goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the highest denomination of the currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an act of the national assembly</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> A floating exchange rate or fluctuating exchange rate is a type of exchange-rate regime in which a currency's value is allowed to fluctuate in response to foreign-exchange market mechanisms. A currency that uses a floating exchange rate is known as a floating currency.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To compare the standard of living among nations, the most widely used economic indicator is the ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">per capital nominal income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">real domestic output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">real gross national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">real per capital income</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income (PCI) or average income measures the average income earned per person in a given area (city, region, country, etc.) in a specified year. It is calculated by dividing the area's total income by its total population. Per capita income is national income divided by population size. It is used to measure the standard of living between two countries.</div>", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING"}, {"id": "objective>Economics>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Statutory organisation usually established by Acts of Parliament are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public corporations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperative societies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint-stock companies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Statutory organizations are usually established by Acts of Parliament and are referred to as public corporations. They are created by the government to undertake commercial activities on its behalf. They are independent legal entities and are typically tasked with specific public functions. The government controls these corporations through board appointments.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A greater burden of the taxes on essential goods is borne by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">higher income group </div>", "<div style=\"font-family:Cambria;font-size:17px;\">newly recruitment workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower income group </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contract workers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is borne by the lower income group as the tax rate on their income bracket is usually higher, and reduces as they earn more.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization and commercialization of public enterprises in Nigeria is necessitated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the IMF conditions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the IBRD conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the government's loss of interest in them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their operational inefficiency</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercialization is the practice of making an activity profitable that was totally free and not under anyone's control. <br/> privatization refers to limiting or annulling government control or interference in an activity and allowing private control to benefit individuals or corporations.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of comparative advantage states that a commodity should be produced in that nation where the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absolute cost is least </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absolute money cost is least</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost is least</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production possibility curve increases</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of comparative advantage describes how, under free trade, an agent will produce more of and consume less of a good for which they have a comparative advantage. In an economic model, agents have a comparative advantage over others in producing a particular good if they can produce that good at a lower relative opportunity cost or autarky price, i.e. at a lower relative marginal cost prior to trade.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of an increase in the personal income tax is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raise the absolute price level </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distort the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the disposable incomes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">by lowering disposable income, an increase in income tax may cause a person to work harder iin order to maintain his previous standard of living. The net effect on income of a higher tax is therefore uncertain..</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important factor hindering the rapid development of the industrial sector in Nigeria.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excessive demand for finished products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the dominance of the oil sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate infrastructure facilities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Problems of industrialization are: <br/> - lack of credit/acess to credit <br/> - over dependence on foreign machines <br/> - inadequate raw material <br/> - production of sub-standard goods <br/> - illiteracy/inadequacy skilled manpower <br/> - lack of basic infrastructure  etc.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for labour is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">competitive demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint demand</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Derived demand is a demand for a commodity or service which is a consequence of the demand for something else.labour is demanded to produce other goods but not for immediate consumption.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major role of multi-national companies in the petroleum industry in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil prospecting only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil marketing only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the establishment of refineries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil marketing and prospecting</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The role played by multinational oil companies in the tremendous expansion of  world petroleum consumption and trade has been one of the great business  successes of modem times. As oil replaced more expensive and less versatile  fuels, the companies opened and serviced vast new markets for crude oil and  petroleum products throughout the industrializing world.They are mainly involved in oil marketing and prospecting.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fixing the prices of agricultural products can be a problem because of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unpredictable output of farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">instability of government policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activities of marketing boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of agricultural exports</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unpredictable output of farmers since farmer lack storage facilities,there output is not predictable and also If the price decline, it will  affects all agricultural products the farmer's equipment may well be practically useless outside agriculture, and alternative opportunities therefore small.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Occupational mobility as applied to factors of production means the case by which </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">factors can be transferred from one placeto another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">factors can be transferred from one form of use to another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resources can be transferred from one place to another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resources can be transformed from one form to another</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Occupational mobility is the ease of movement of resources between jobs. For example, a worker leaves a job as an accountant to take a job as a computer programmer. Some factors are highly mobile and thus are easily switched.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force of a country can be determined by examining the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sex distribution of the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Occupations distribution of the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">age structure of the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geographical distribution of the population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Age structure of the population will determine the size of the labour force. Usually, an active labour force will be from 18 - 65 years.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two basic features common to an industry are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">similarity of products and production processes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similarity of products and source of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production processes and source of capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of capital and labour supply</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An industry is a branch of an economy that produces a closely related set of raw materials, goods, or services or producing similar goods.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country is said to be over-populated when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there are too many able-bodied men and women in the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the resources are more than enough to cater for the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the size of the population is greater than the annual budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the resources are inadequate to cater for the population</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Overpopulation is a function of the number of individuals compared to the relevant resources, such as the water and essential nutrients they need to survive. It can result from an increase in births, a decline in mortality rates, an increase in immigration, or an unsustainable biome and depletion of resources.</div>", "topic": "POPULATION : OVER POPULATION, UNDER POPULATION"}, {"id": "objective>Economics>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a union is composed of workers with same skill, it is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an industrial union </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a workers' union</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a craft union </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a technical union</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Craft union is a labor union with membership limited to workers of the same craft. It is a union representing workers who share the same skill-set or who perform identical tasks, although they may work in different industries; for example, electricians and plumbers.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An adverse environmental impact of the petroleum industry on the economy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the vandalisation of oil equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil spillage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">communal riots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community development</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The environmental impact of petroleum is negative because it is toxic to all forms of life and its extraction fuels climate change. It leads to oil spill which is the release of a liquid petroleum hydrocarbon into the environment, especially the marine ecosystem, due to human activity, and is a form of pollution. </div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}];
